// upstream/src/modes/agent/parse-tools.ts
function parseAllowedTools(claudeArgs) {
  const patterns = [
    /--(?:allowedTools|allowed-tools)\s+"([^"]+)"/g,
    /--(?:allowedTools|allowed-tools)\s+'([^']+)'/g,
    /--(?:allowedTools|allowed-tools)\s+([^'"\s][^\s]*)/g
  ];
  const tools = [];
  const seen = new Set;
  for (const pattern of patterns) {
    for (const match of claudeArgs.matchAll(pattern)) {
      if (match[1]) {
        if (match[1].startsWith("--")) {
          continue;
        }
        for (const tool of match[1].split(",")) {
          const trimmed = tool.trim();
          if (trimmed && !seen.has(trimmed)) {
            seen.add(trimmed);
            tools.push(trimmed);
          }
        }
      }
    }
  }
  return tools;
}

