    const allowedBots = githubContext.inputs.allowedBots;
    if (allowedBots.trim() === "*") {
      console.log(`All bots are allowed, skipping human actor check for: ${githubContext.actor}`);
      return;
    }
    const allowedBotsList = allowedBots.split(",").map((bot) => bot.trim().toLowerCase().replace(/\[bot\]$/, "")).filter((bot) => bot.length > 0);
