function extractUserRequest(commentBody, triggerPhrase) {
  if (!commentBody) {
    return null;
  }
  const triggerIndex = commentBody.toLowerCase().indexOf(triggerPhrase.toLowerCase());
  if (triggerIndex === -1) {
    return null;
  }
  const afterTrigger = commentBody.substring(triggerIndex + triggerPhrase.length).trim();
  return afterTrigger || null;
}

