function ensureProperlyEncodedUrl(url) {
  try {
    new URL(url);
    if (url.includes(" ")) {
      const [baseUrl, queryString] = url.split("?");
      if (queryString) {
        const params = new URLSearchParams;
        const pairs = queryString.split("&");
        for (const pair of pairs) {
          const [key, value = ""] = pair.split("=");
          if (key) {
            params.set(key, decodeURIComponent(value));
          }
        }
        return `${baseUrl}?${params.toString()}`;
      }
      return url.replace(/ /g, "%20");
    }
    return url;
  } catch (e) {
    try {
      let fixedUrl = url.replace(/ /g, "%20");
      const urlParts = fixedUrl.split("?");
      if (urlParts.length > 1 && urlParts[1]) {
        const [baseUrl, queryString] = urlParts;
        const fixedQuery = queryString.replace(/([^%]|^):(?!%2F%2F)/g, "$1%3A");
        fixedUrl = `${baseUrl}?${fixedQuery}`;
      }
      new URL(fixedUrl);
      return fixedUrl;
    } catch {
      return null;
    }
  }
}
function selectClosingLine(seed) {
  let hash = 2166136261;
  for (let index = 0;index < seed.length; index += 1) {
    hash ^= seed.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  const lineIndex = (hash >>> 0) % CLOSING_LINES.length;
  return CLOSING_LINES[lineIndex] ?? CLOSING_LINES[0];
}
