import { existsSync, statSync } from "fs";
import { mkdir as mkdir4, writeFile as writeFile4 } from "fs/promises";
async function validateAndPreparePrompt(input) {
  if (!input.prompt && !input.promptFile) {
    throw new Error("Neither 'prompt' nor 'prompt_file' was provided. At least one is required.");
  }
  if (input.prompt && input.promptFile) {
    throw new Error("Both 'prompt' and 'prompt_file' were provided. Please specify only one.");
  }
  if (input.promptFile) {
    if (!existsSync(input.promptFile)) {
      throw new Error(`Prompt file '${input.promptFile}' does not exist.`);
    }
    const stats = statSync(input.promptFile);
    if (stats.size === 0) {
      throw new Error("Prompt file is empty. Please provide a non-empty prompt.");
    }
    return {
      type: "file",
      path: input.promptFile
    };
  }
  if (!input.prompt || input.prompt.trim().length === 0) {
    throw new Error("Prompt is empty. Please provide a non-empty prompt.");
  }
  const inlinePath = "/tmp/claude-action/prompt.txt";
  return {
    type: "inline",
    path: inlinePath
  };
}
async function createTemporaryPromptFile(prompt, promptPath) {
  const dirPath = promptPath.substring(0, promptPath.lastIndexOf("/"));
  await mkdir4(dirPath, { recursive: true });
  await writeFile4(promptPath, prompt);
}
async function preparePrompt(input) {
  const config = await validateAndPreparePrompt(input);
  if (config.type === "inline") {
    await createTemporaryPromptFile(input.prompt, config.path);
  }
  return config;
}

