  const hasImages = imageUrlMap && imageUrlMap.size > 0;
  const repository = `${context2.repository.owner}/${context2.repository.repo}`;
  const entityType = context2.isPR ? "pull request" : "issue";
  const closingKeyword = !context2.isPR ? `Closes #${context2.entityNumber}` : undefined;
