var body_default = `{description}

**Context**
{context}

**Affected Files**
{affected_files}

**Requirements**
{requirements}

{divider}

**Verification**
{verification_commands}

**Not In Scope**
{not_in_scope}

**Evidence**
{evidence}

{depends_on}

<sub>Arasaka Queue Planning Division.</sub>
`;

// src/render/chrome.ts
function wrapArtifactBody(params) {
  const content = params.body.trim();
  const parts = [];
  if (params.banner !== false) {
    parts.push(`<img src="${ASSET_BASE}/banner.svg" />`);
  }
  if (params.replyAsset) {
    parts.push(`<img src="${ASSET_BASE}/${params.replyAsset}" />`);
  }
  parts.push("", content, "", `<img src="${ASSET_BASE}/footer.svg" />`);
  return parts.join(`
`);
}

// src/render/template.ts
function renderTemplate2(template, values) {
  return Object.entries(values).reduce((output, [key, value]) => output.replace(new RegExp(`\\{${key}\\}`, "g"), value), template);
}
function renderBulletList(items, emptyText) {
  if (items.length === 0) {
    return emptyText;
  }
  return items.map((item) => `- ${item}`).join(`
`);
}
function renderCheckboxList(items, emptyText) {
  if (items.length === 0) {
    return emptyText;
  }
  return items.map((item) => `- [ ] ${item}`).join(`
`);
}
function renderAffectedFileList(files, emptyText) {
  if (files.length === 0) {
    return emptyText;
  }
  return files.map((f) => {
    const loc = f.line !== undefined ? `\`${f.path}:${f.line}\`` : `\`${f.path}\``;
    return `- ${loc} \u2014 ${f.note}`;
  }).join(`
`);
}
function renderEvidenceList(items, emptyText) {
  if (items.length === 0) {
    return emptyText;
  }
  return items.map((e2) => `- \`${e2.location}\` \u2014 ${e2.observation}`).join(`
`);
}
function renderDependsOn(issueNumbers) {
  if (!issueNumbers || issueNumbers.length === 0) {
    return "";
  }
  const links = issueNumbers.map((n2) => `#${n2}`).join(", ");
  return `**Dependencies**
Depends on ${links}.`;
}

// src/render/issue.ts
function renderIssueBody(input) {
  const divider = `<img src="${ASSET_BASE}/divider.svg" />`;
  const body = renderTemplate2(body_default, {
    divider,
    description: input.description.trim(),
    context: input.context.trim(),
    affected_files: renderAffectedFileList(input.affectedFiles, "- No affected files were identified."),
    requirements: renderCheckboxList(input.requirements, "- No requirements were supplied."),
    verification_commands: renderBulletList(input.verificationCommands, "- No verification commands were supplied."),
    not_in_scope: renderBulletList(input.notInScope, "- No scope exclusions were specified."),
    evidence: renderEvidenceList(input.evidence, "- No repository evidence was supplied."),
    depends_on: renderDependsOn(input.dependsOn)
  }).trim();
  return wrapArtifactBody({ body });
}

