// src/publish/develop.ts
async function enableAutoMerge(octokit, pullRequestNodeId) {
  if (!pullRequestNodeId) {
    return;
  }
  try {
    await octokit.graphql(`
        mutation EnableAutoMerge($pullRequestId: ID!) {
          enablePullRequestAutoMerge(
            input: { pullRequestId: $pullRequestId, mergeMethod: SQUASH }
          ) {
            pullRequest {
              number
            }
          }
        }
      `, { pullRequestId: pullRequestNodeId });
  } catch (error3) {
    console.warn("[arasaka] Failed to enable auto-merge:", error3);
  }
}
function ensureRemoteBranch(branchName) {
  try {
    execFileSync4("git", ["push", "--set-upstream", "origin", branchName], { stdio: "pipe" });
  } catch (error3) {
    throw new Error(`Failed to push implementation branch '${branchName}' before PR publication: ${String(error3)}`);
  }
}
async function publishDevelopOutput(params) {
  const { octokit, context: context2, rawStructuredOutput, issueNumber, branchName, baseBranch } = params;
  const parsed = developOutputSchema.parse(JSON.parse(rawStructuredOutput));
  const { owner, repo } = context2.repository;
  if (!branchName) {
    throw new Error("Missing branch name for develop publication");
  }
  ensureRemoteBranch(branchName);
  const body = parsed.pull_request.body ? wrapArtifactBody({
    body: `${parsed.pull_request.body.trim()}

Closes #${issueNumber}`
  }) : renderPullRequestBody({
    summary: parsed.pull_request.summary,
    changes: parsed.pull_request.changes,
    verification: parsed.pull_request.verification,
    assumptions: parsed.pull_request.assumptions,
    closingIssueNumber: issueNumber
  });
  const { data: existingPullRequests } = await octokit.rest.pulls.list({
    owner,
    repo,
    state: "open",
    head: `${owner}:${branchName}`,
    per_page: 10
  });
  let pullRequestNumber;
  let pullRequestUrl;
  let pullRequestTitle;
  let pullRequestNodeId;
  let action = "updated";
  if (existingPullRequests[0]) {
    const { data } = await octokit.rest.pulls.update({
      owner,
      repo,
      pull_number: existingPullRequests[0].number,
      body,
      base: baseBranch
    });
    pullRequestNumber = data.number;
    pullRequestUrl = data.html_url;
    pullRequestTitle = data.title;
    pullRequestNodeId = data.node_id ?? null;
  } else {
    const { data } = await octokit.rest.pulls.create({
      owner,
      repo,
      title: parsed.pull_request.title,
      body,
      head: branchName,
      base: baseBranch
    });
    pullRequestNumber = data.number;
    pullRequestUrl = data.html_url;
    pullRequestTitle = data.title;
    pullRequestNodeId = data.node_id ?? null;
    action = "created";
  }
  await enableAutoMerge(octokit, pullRequestNodeId);
  let issueCommentUrl = "";
  if (action === "created") {
    const issueCommentBody = renderIssueCommentBody({
      summary: parsed.issue_comment.summary,
      verification: parsed.issue_comment.verification,
      followUps: parsed.issue_comment.follow_ups,
      prUrl: pullRequestUrl
    });
    const progressCommentId = Number(process.env.ARTIFACT_PROGRESS_COMMENT_ID) || 0;
    const { data: comment } = progressCommentId ? await octokit.rest.issues.updateComment({
      owner,
      repo,
      comment_id: progressCommentId,
      body: issueCommentBody
    }) : await octokit.rest.issues.createComment({
      owner,
      repo,
      issue_number: issueNumber,
      body: issueCommentBody
    });
    issueCommentUrl = comment.html_url;
  }
  return {
    status: "implemented",
    pull_request: {
      number: pullRequestNumber,
      url: pullRequestUrl,
      title: pullRequestTitle,
      action
    },
    issue_comment_url: issueCommentUrl
  };
}

