async function installClaudeCode() {
  const customExecutable = process.env.PATH_TO_CLAUDE_CODE_EXECUTABLE;
  if (customExecutable) {
    console.log(`Using custom Claude Code executable: ${customExecutable}`);
    const claudeDir = dirname2(customExecutable);
    const githubPath = process.env.GITHUB_PATH;
    if (githubPath) {
      await appendFile(githubPath, `${claudeDir}
`);
    }
    process.env.PATH = `${claudeDir}:${process.env.PATH}`;
    return;
  }
  const claudeCodeVersion = "2.1.81";
  console.log(`Installing Claude Code v${claudeCodeVersion}...`);
  for (let attempt = 1;attempt <= 3; attempt++) {
    console.log(`Installation attempt ${attempt}...`);
    try {
      await new Promise((resolve, reject) => {
        const child = spawn2("bash", [
          "-c",
          `curl -fsSL https://claude.ai/install.sh | bash -s -- ${claudeCodeVersion}`
        ], { stdio: "inherit" });
        child.on("close", (code) => {
          if (code === 0)
            resolve();
          else
            reject(new Error(`Install failed with exit code ${code}`));
        });
        child.on("error", reject);
      });
      console.log("Claude Code installed successfully");
      const homeBin = `${process.env.HOME}/.local/bin`;
      const githubPath = process.env.GITHUB_PATH;
      if (githubPath) {
        await appendFile(githubPath, `${homeBin}
`);
      }
      process.env.PATH = `${homeBin}:${process.env.PATH}`;
      return;
    } catch (error3) {
      if (attempt === 3) {
        throw new Error(`Failed to install Claude Code after 3 attempts: ${error3}`);
      }
      console.log("Installation failed, retrying...");
      await new Promise((resolve) => setTimeout(resolve, 5000));
    }
  }
}
var TRANSIENT_ERROR_RE = /API Error: (?:429|529)\b|overloaded_error|rate_limit/i;
var MAX_SDK_ATTEMPTS = 5;
var SDK_RETRY_DELAYS = [30000, 60000, 120000, 180000];
async function runClaudeWithRetry(promptPath, options) {
  for (let attempt = 1;attempt <= MAX_SDK_ATTEMPTS; attempt++) {
    try {
      return await runClaude(promptPath, options);
    } catch (error3) {
      const message = error3 instanceof Error ? error3.message : String(error3);
      const isTransient = TRANSIENT_ERROR_RE.test(message);
      if (!isTransient || attempt === MAX_SDK_ATTEMPTS) {
        throw error3;
      }
      const delay = SDK_RETRY_DELAYS[attempt - 1];
      console.log(`[arasaka] Transient API error on attempt ${attempt}/${MAX_SDK_ATTEMPTS}, retrying in ${delay / 1000}s: ${message}`);
      await new Promise((resolve) => setTimeout(resolve, delay));
    }
  }
  throw new Error("unreachable");
}
async function writeStepSummary(executionFile) {
  const summaryFile = process.env.GITHUB_STEP_SUMMARY;
  if (!summaryFile)
    return;
  try {
    const fileContent = readFileSync2(executionFile, "utf-8");
    const data = JSON.parse(fileContent);
    const markdown = formatTurnsFromData(data);
    await appendFile(summaryFile, markdown);
    console.log("Successfully formatted Claude Code report");
  } catch (error3) {
    console.error(`Failed to format output: ${error3}`);
    try {
      let fallback = `## Claude Code Report (Raw Output)

`;
      fallback += `Failed to format output (please report). Here's the raw JSON:

`;
      fallback += "```json\n";
      fallback += readFileSync2(executionFile, "utf-8");
      fallback += "\n```\n";
      await appendFile(summaryFile, fallback);
    } catch {
      console.error("Failed to write raw output to step summary");
    }
  }
}
